class Solution:
    def maximumTripletValue(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    val = (nums[i] - nums[j]) * nums[k]
                    if val > best:
                        best = val
        return best

