class Solution:
    def maximumTripletValue(self, nums):
        n = len(nums)
        suffix_max = [0] * n
        suffix_max[-1] = nums[-1]
        for i in range(n - 2, -1, -1):
            suffix_max[i] = max(suffix_max[i + 1], nums[i])
        best = 0
        prefix_best = nums[0]
        for j in range(1, n - 1):
            candidate = (prefix_best - nums[j]) * suffix_max[j + 1]
            if candidate > best:
                best = candidate
            if nums[j] > prefix_best:
                prefix_best = nums[j]
        return best

