var maximumTripletValue = function(nums) {
    const n = nums.length;
    const suffixMax = new Array(n);
    suffixMax[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        suffixMax[i] = Math.max(suffixMax[i + 1], nums[i]);
    }
    let best = 0;
    let prefixBest = nums[0];
    for (let j = 1; j < n - 1; j++) {
        const candidate = (prefixBest - nums[j]) * suffixMax[j + 1];
        if (candidate > best) best = candidate;
        if (nums[j] > prefixBest) prefixBest = nums[j];
    }
    return best;
};
